obtener index [0] ƒ:
(texto) => {
    const regex = /^\[(\d+)\]\s*(.*)$/;
    const match = texto.match(regex);

    if (!match) {
        throw new Error('Formato inválido. Se esperaba: "[número] texto"');
    }

    return {
        indice: parseInt(match[1], 10),
        texto: match[2].trim(),
    };
}

· ~ abrir ƒ:
(dataset) => {
    // Si el chip no está visible, anclamos al puntero en vez de reventar.
    const chip_ancla = diarsaba.get(`${dataset.parent} ֎`);
    const rect = (chip_ancla instanceof Element)
        ? chip_ancla.getBoundingClientRect()
        : { left: diarsaba.get("pointer x") || 0, top: diarsaba.get("pointer y") || 0, width: 0 };
    const l_div = diarsaba.get("create list ƒ")(
        rect.left + rect.width + 10,
        rect.top,
        diarsaba.get(dataset.parent),
        dataset.parent
    );

    if (diarsaba.get(`${dataset.parent} # ֎`)) {
        diarsaba.get(`${dataset.parent} # ֎`).remove();
    }

    diarsaba.set(`${dataset.parent} # ֎`, l_div);
}

