() => {

    const event = diarsaba.get("pointer up event");
    const target = event.target;
    const content = target.textContent;

    if (content == "diarsaba-map @") {

        // 1. Calculamos los límites de la ventana UNA VEZ fuera del bucle (mejor rendimiento)
        // Añadimos un "margen" para que los chips no queden cortados en los bordes de la pantalla
        const margen = 50;
        const maximoX = window.innerWidth - margen;
        const maximoY = window.innerHeight - margen;

        diarsaba.forEach((valor, clave) => {
            // 2. Generamos las coordenadas aleatorias
            // Math.random() da un decimal entre 0 y 1. Lo multiplicamos por el máximo.
            // Usamos Math.floor() para redondear a números enteros (los píxeles suelen ser enteros)
            // Sumamos el margen para que empiece desde el margen y no desde el 0 absoluto.
            const xAleatorio = Math.floor(Math.random() * maximoX) + margen;
            const yAleatorio = Math.floor(Math.random() * maximoY) + margen;

            // 3. Llamamos a la función con los nuevos valores
            const chip = diarsaba.get("create chip ƒ")(
                xAleatorio,
                yAleatorio,
                clave,
                "",
                clave.slice(-1)
            );
        });

        //en caso opuesto a esto, mejor crear una lista y que habra automaticamente en el editor
    } else {
        // Las referencias ֎ apuntan a nodos que están a punto de
        // desaparecer: se limpian antes de repintar.
        for (const k of [...diarsaba.keys()]) {
            if (typeof k === "string" && k.endsWith("֎") && diarsaba.get(k) instanceof Element) {
                diarsaba.delete(k);
            }
        }
        document.body.replaceChildren();

        const chip = diarsaba.get("create chip ƒ")(
            100,
            50,
            content,
            "",
            content.slice(-1)
        );
        diarsaba.set(`${content} ֎`, chip);

        // Desestructuramos el array en [clave, valor]
        let place = diarsaba.get(content)
        Object.entries(place).forEach(([clave, valor]) => {
            const chip = diarsaba.get("create chip ƒ")(
                valor.x,
                valor.y,
                clave,
                "",
                clave.slice(-1)
            );

            // Sin esta referencia, abrir/ocultar/padre no encuentran el
            // chip y anclan al puntero: el hijo sale desplazado.
            diarsaba.set(`${clave} ֎`, chip);
        });


        diarsaba.set("current place §", content)
    }



}

