p2p ƒ @ stream ƒ:
(id, peer) => {
    // Un Stream vive en Go; aquí llega su identificador. Esto lo envuelve.
    //
    // Por el cable va JSON. Se eligió sobre msgpack por dos razones, y ninguna
    // es el tamaño: (1) un átomo de carga JSON es un mapa ":", que en diarsaba
    // tiene tipo y por tanto editor —msgpack obligaba a un átomo sin sigilo,
    // que no se puede abrir ni despachar—; y (2) cualquier peer puede hablarlo,
    // incluida la CLI de p2plite. window.msgpack sigue disponible para cuando
    // haga falta binario de verdad.
    //
    // El base64 de abajo NO es el formato: es el salto Go↔JS, que es JSON por
    // definición de los bindings de Wails y codifica []byte en base64.
    const aB64 = (texto) => {
        const bytes = new TextEncoder().encode(texto);
        let bin = "";
        for (const b of bytes) bin += String.fromCharCode(b);
        return btoa(bin);
    };
    const deB64 = (b64) =>
        new TextDecoder().decode(Uint8Array.from(atob(b64), (c) => c.charCodeAt(0)));

    return {
        id,
        peer: peer || "",
        escribir: async (valor) => {
            // Un string se manda tal cual: así se puede hablar con un peer que
            // espera texto plano sin envolverlo en comillas JSON.
            const texto = typeof valor === "string" ? valor : JSON.stringify(valor);
            return await window.p2p.StreamWrite(id, aB64(texto));
        },
        // Termina de hablar sin cerrar: el otro lado lee hasta el final y contesta.
        termine: async () => await window.p2p.StreamCloseWrite(id),
        leer: async () => {
            let texto = "";
            for (;;) {
                const c = await window.p2p.StreamRead(id, 0, 0);
                if (c.data) texto += deB64(c.data);
                if (c.eof) break;
            }
            if (texto === "") return null;
            // Si no es JSON se devuelve el texto tal cual en vez de reventar:
            // así el place entiende a la CLI de p2plite y a cualquier peer que
            // mande texto plano.
            try {
                return JSON.parse(texto);
            } catch (_) {
                return texto;
            }
        },
        cerrar: async () => await window.p2p.StreamClose(id),
    };
}

