p2p ƒ @ OpenStream ƒ:
async (peer, datos) => {
    const dice = diarsaba.get("p2p ƒ @ dice ƒ");
    const arg = diarsaba.get("p2p ƒ @ arg ƒ");
    let s = null;
    try {
        // Sin peer explícito se usa el último que dejó FindProviders.
        const p = arg(peer) || diarsaba.get("p2p ƒ @ peer §");
        if (!p) return dice("OpenStream ✗", "sin peer: corre FindProviders antes, o pásale uno");

        // La carga por defecto es un mapa ":": editable con · : editor ƒ (Monaco
        // en modo json, que valida al guardar).
        const carga = datos === undefined ? diarsaba.get("p2p ƒ @ enviar :") : arg(datos);
        s = diarsaba.get("p2p ƒ @ stream ƒ")(await window.p2p.OpenStream(p, 30000), p);

        await s.escribir(carga === undefined ? null : carga);
        await s.termine(); // le decimos que terminamos: ahora puede contestar

        // Que no conteste NO es un fallo: el mensaje ya está entregado. Pasa
        // siempre que el otro lado tenga la respuesta automática apagada y no
        // haya nadie para pulsar Reply !. Antes esto salía como error y parecía
        // que el envío no había funcionado.
        let respuesta;
        let hubo = true;
        try {
            respuesta = await s.leer();
        } catch (e) {
            hubo = false;
        }
        await s.cerrar();

        if (!hubo) {
            return dice("OpenStream", {
                a: p.slice(-8),
                envié: carga,
                nota: "entregado, pero no contestó. Si esperabas respuesta, mira «p2p ƒ @ auto responder §» en el OTRO nodo: vacío = alguien tiene que pulsar Reply ! allí.",
            });
        }

        diarsaba.set("p2p ƒ @ respuesta", respuesta);
        return dice("OpenStream", { a: p.slice(-8), envié: carga, contestó: respuesta });
    } catch (e) {
        if (s) {
            try {
                await s.cerrar();
            } catch (_) {}
        }
        return dice("OpenStream ✗", e);
    }
}

p2p ƒ @ StreamHandle ƒ:
async () => {
    // Deja la app lista para RECIBIR. La llama "on start ƒ", así que no hace
    // falta tocarla: al abrir la app ya se escucha.
    //
    // Lo entrante se apila en "Streams #". Qué pasa después lo deciden dos
    // átomos:
    //   - "p2p ƒ @ auto responder §": con valor, se acusa recibo y se cierra
    //     (permite dejar la app sola); vacío, el stream queda abierto para
    //     Reply !.
    //   - "p2p ƒ @ devolver en $": segundos tras los cuales se le manda a ese
    //     peer el contenido de "enviar :". 0 lo apaga.
    const dice = diarsaba.get("p2p ƒ @ dice ƒ");
    try {
        // Idempotente: suscribirse dos veces duplicaría cada entrada.
        if (diarsaba.get("p2p ƒ @ escuchando ֎")) return "ya escuchaba";

        diarsaba.set(
            "p2p ƒ @ escuchando ֎",
            window.EventsOn("p2p:stream", async (ev) => {
                try {
                    const s = diarsaba.get("p2p ƒ @ stream ƒ")(ev.stream, ev.from);
                    // Se lee hasta el final ANTES de decidir: así "data" ya
                    // trae el mensaje, se conteste o no.
                    const data = await s.leer();
                    const auto = diarsaba.get("p2p ƒ @ auto responder §");
                    const hora = new Date().toLocaleTimeString();

                    // Con el ida y vuelta puesto llega un mensaje por ronda,
                    // casi siempre idéntico al anterior. Si se apilaran todos,
                    // "Streams #" sería una pared de repeticiones donde no se
                    // ve lo que de verdad cambió. Un repetido solo actualiza su
                    // hora y su cuenta.
                    const previas = diarsaba.get("Streams #") || [];
                    const ultima = previas.find((e) => e.peer === ev.from);
                    const repetido =
                        ultima && JSON.stringify(ultima.data) === JSON.stringify(data);

                    if (repetido) {
                        ultima.hora = hora;
                        ultima.veces = (ultima.veces || 1) + 1;
                        ultima.id = ev.stream;
                        ultima.contestada = !!auto;
                        diarsaba.set("Streams #", [...previas]);
                    } else {
                        const tope = Number(diarsaba.get("p2p ƒ @ historial $")) || 50;
                        const entrada = {
                            id: ev.stream,
                            peer: ev.from,
                            data,
                            hora,
                            veces: 1,
                            // Con acuse automático el stream ya está cerrado,
                            // así que Reply ! no puede usarlo: queda marcada.
                            contestada: !!auto,
                            // Sin esto la lista dibuja "[object Object]":
                            // create list ƒ interpola el elemento.
                            toString() {
                                const d =
                                    typeof this.data === "string" ? this.data : JSON.stringify(this.data);
                                const n = this.veces > 1 ? ` ×${this.veces}` : "";
                                return `${this.contestada ? "✓" : this.id} ${this.hora} ← ${this.peer.slice(-8)}${n}: ${d}`;
                            },
                        };
                        diarsaba.set("Streams #", [entrada, ...previas].slice(0, tope));
                    }

                    if (auto) {
                        // El acuse devuelve lo recibido: confirma la entrega y
                        // de paso que el viaje de ida no deformó nada.
                        await s.escribir({ ok: true, recibido: data });
                        await s.cerrar();
                    }

                    // Y se programa la vuelta, que es lo que mantiene el flujo.
                    diarsaba.get("p2p ƒ @ devolver ƒ")(ev.from);

                    console.log(
                        "[p2p ƒ] entrante de",
                        ev.from.slice(-8),
                        repetido ? "(repetido)" : data,
                        auto ? "(acusado)" : "(abierto)"
                    );
                } catch (e) {
                    console.error("[p2p ƒ] entrante falló", e);
                }
            })
        );

        await window.p2p.Start();
        return dice("StreamHandle", "escuchando: lo entrante aparece en «Streams #»");
    } catch (e) {
        // Sin alert: esto corre al arrancar y un modal dejaría la app
        // inservible. El fallo queda en la consola y en "p2p ƒ @ dice §".
        diarsaba.set("p2p ƒ @ dice §", `StreamHandle ✗\n${e.message || e}`);
        console.error("[p2p ƒ] no se pudo escuchar:", e);
        return e;
    }
}

p2p ƒ @ Reply ƒ:
async (id, datos) => {
    // Contesta un stream de "Streams #" y lo cierra. El id puede venir como
    // string, como nombre de un átomo, o como la entrada entera (si le pasas
    // el objeto de la lista).
    const dice = diarsaba.get("p2p ƒ @ dice ƒ");
    const arg = diarsaba.get("p2p ƒ @ arg ƒ");
    try {
        let sid = arg(id);
        if (sid && typeof sid === "object" && sid.id) sid = sid.id;
        // Sin id: se contesta el más reciente, que es lo que se querrá el 90%.
        if (!sid) {
            const pendientes = diarsaba.get("Streams #") || [];
            if (!pendientes.length) return dice("Reply ✗", "no hay streams entrantes que contestar");
            sid = pendientes[0].id;
        }

        const carga = datos === undefined ? diarsaba.get("p2p ƒ @ responder :") : arg(datos);
        // Un stream ya acusado está cerrado en Go: contestar ahí falla
        // con un "stream desconocido" que no explica nada.
        const entrada = (diarsaba.get("Streams #") || []).find((e) => e.id === sid);
        if (entrada && entrada.contestada) {
            return dice("Reply ✗", `${sid} ya se contestó sola (auto responder está activo).\n\nPara contestar a mano, vacía "p2p ƒ @ auto responder §" y pide que te lo manden otra vez.`);
        }

        const s = diarsaba.get("p2p ƒ @ stream ƒ")(sid, "");
        await s.escribir(carga === undefined ? null : carga);
        await s.cerrar();

        // Fuera de la lista: ya está contestado y cerrado.
        diarsaba.set("Streams #", (diarsaba.get("Streams #") || []).filter((e) => e.id !== sid));
        return dice("Reply", `contestado ${sid}`);
    } catch (e) {
        return dice("Reply ✗", e);
    }
}

install mover ƒ:
() => {
    // Arrastre de chips. Es un MODO —lo enciende "mover !" en el menú
    // principal— porque mientras está activo el clic no abre ni edita.
    //
    // Los listeners van en window y solo deben registrarse una vez; la marca
    // ֎ no se persiste, así que cada arranque los pone de nuevo.
    if (diarsaba.get("mover instalado ֎")) return;
    diarsaba.set("mover instalado ֎", true);

    let arrastrando = null;
    let dx = 0;
    let dy = 0;

    // Capture: hay que llegar ANTES que los listeners de on start ƒ para poder
    // cortar el clic que abriría el chip.
    window.addEventListener(
        "pointerdown",
        (e) => {
            if (!diarsaba.get("moviendo chips §")) return;
            // Solo el botón primario: el derecho abre el menú, y es por donde
            // se sale del modo.
            if (e.button !== 0) return;
            const chip = e.target.closest(".object-name");
            if (!chip) return;
            const r = chip.getBoundingClientRect();
            arrastrando = chip;
            dx = e.clientX - r.left;
            dy = e.clientY - r.top;
            chip.setPointerCapture?.(e.pointerId);
            chip.classList.add("arrastrando");
            e.stopPropagation();
            e.preventDefault();
        },
        true
    );

    window.addEventListener(
        "pointermove",
        (e) => {
            if (!arrastrando) return;
            arrastrando.style.left = `${e.clientX - dx}px`;
            arrastrando.style.top = `${e.clientY - dy}px`;
            e.stopPropagation();
        },
        true
    );

    window.addEventListener(
        "pointerup",
        (e) => {
            if (!arrastrando) return;
            const chip = arrastrando;
            arrastrando = null;
            chip.classList.remove("arrastrando");

            // La posición se guarda en el place actual, que es donde vive la
            // disposición. Si el átomo no está en el place (p. ej. un chip
            // hijo abierto), se mueve pero no se registra: no tiene sitio ahí.
            const nombre = chip.textContent;
            const placeName = diarsaba.get("current place §");
            const place = diarsaba.get(placeName);
            if (place && typeof place === "object" && nombre in place) {
                diarsaba.set(placeName, {
                    ...place,
                    [nombre]: { x: parseFloat(chip.style.left) || 0, y: parseFloat(chip.style.top) || 0 },
                });
            }

            // Cortamos el clic: si no, al soltar se abriría el chip.
            e.stopPropagation();
            e.preventDefault();
        },
        true
    );
}

open submenu ƒ:
(nombre, target) => {
    // Dibuja el contenido de una lista "#" como submenú, con la misma función
    // que el menú principal — así un submenú ES un menú: sus ítems se pulsan
    // igual y una lista dentro de otra vuelve a abrirse aquí, anidando sola.
    //
    // Devuelve false si el átomo no es una lista, para que quien llama siga su
    // camino normal.
    const lista = diarsaba.get(nombre);
    if (!Array.isArray(lista)) return false;

    // Pulsar dos veces el mismo ítem no debe apilar submenús.
    const previo = diarsaba.get(`${nombre} submenu ֎`);
    if (previo && typeof previo.remove === "function") previo.remove();

    const r = target.getBoundingClientRect();
    const sub = diarsaba.get("create list menu ƒ")(lista, nombre, "", r.right + 6, r.top);
    // La marca permite a "clear menus ƒ" barrerlos todos sin llevar la cuenta.
    sub.classList.add("submenu");
    diarsaba.set(`${nombre} submenu ֎`, sub);
    return true;
}

· @ editor ƒ:
async (dataset) => {
    const actual = diarsaba.get(dataset.parent) || {};
    const res = await window.codeEditor.open(
        dataset.parent,
        JSON.stringify(actual, null, 2),
        "json"
    );
    if (res == null || res.trim() === "") return;

    let nuevo;
    try {
        nuevo = JSON.parse(res);
    } catch (e) {
        alert(`"${dataset.parent}" no se guardó: el JSON no es válido.\n\n${e.message}`);
        return;
    }
    // Un objeto no puede volver como número o texto: eso rompería a quien lo lee.
    if (nuevo === null || typeof nuevo !== "object" || Array.isArray(nuevo)) {
        alert(`"${dataset.parent}" no se guardó: tiene que ser un objeto {…}.`);
        return;
    }
    diarsaba.set(dataset.parent, nuevo);
}

p2p ƒ @ devolver ƒ:
(peer) => {
    // Programa el envío de "enviar :" a ese peer. Es lo que mantiene vivo el
    // ida y vuelta: cada lado contesta al otro una vez por ronda.
    const segundos = Number(diarsaba.get("p2p ƒ @ devolver en $")) || 0;
    if (!segundos || !peer) return; // 0 = apagado

    // UN SOLO temporizador por peer. Sin esto, dos mensajes seguidos
    // programarían dos envíos, cada uno provocaría otro del otro lado, y el
    // tráfico se doblaría en cada vuelta hasta ahogar a los dos nodos.
    const pendientes = diarsaba.get("p2p ƒ @ pendientes ֎") || {};
    if (pendientes[peer]) return;

    pendientes[peer] = setTimeout(async () => {
        const p = diarsaba.get("p2p ƒ @ pendientes ֎") || {};
        delete p[peer];
        diarsaba.set("p2p ƒ @ pendientes ֎", p);

        try {
            const s = diarsaba.get("p2p ƒ @ stream ƒ")(await window.p2p.OpenStream(peer, 30000), peer);
            await s.escribir(diarsaba.get("p2p ƒ @ enviar :"));
            await s.termine();
            // El acuse del otro lado, si lo tiene puesto. Que no llegue no
            // importa: lo que cuenta es que el mensaje salió.
            try {
                await s.leer();
            } catch (_) {}
            await s.cerrar();
            console.log("[p2p ƒ] devuelto a", peer.slice(-8));
        } catch (e) {
            // Si el otro lado se fue, el ida y vuelta se corta AQUÍ y no se
            // reanuda solo: volverá a arrancar cuando alguien mande algo a
            // mano con OpenStream !.
            console.error("[p2p ƒ] no se pudo devolver a", peer.slice(-8), e.message || e);
        }
    }, segundos * 1000);

    diarsaba.set("p2p ƒ @ pendientes ֎", pendientes);
}

mover ƒ:
() => {
    // Enciende o apaga el modo mover. Sin botón a la vista, la única señal de
    // que está activo es el borde del lienzo y el cursor sobre los chips: por
    // eso el borde, y no solo el cursor.
    const activo = !diarsaba.get("moviendo chips §");
    diarsaba.set("moviendo chips §", activo ? "si" : "");
    document.body.classList.toggle("moviendo-chips", activo);
    return activo ? "moviendo" : "quieto";
}
